    var _sh3 = document.getElementById('ag-panel-host') && document.getElementById('ag-panel-host').shadowRoot;
    var _mb = _sh3 && _sh3.getElementById('ag-mini-btn');
    if (_mb) { _mb.dataset.on='false'; _mb.innerHTML='&#9654; Iniciar'; }
