      const sumRows = Object.entries(byItem).sort((a,b)=>b[1].usd-a[1].usd).map(([item,v]) =>
        '<tr><td><div class="item-name">'+escHtml(item)+'</div></td><td class="qty">'+v.count+'x</td><td class="qty">'+v.qty.toLocaleString('pt-BR')+'</td><td class="price-tok">$'+v.usd.toFixed(2)+'</td></tr>').join('');
      const detRows = sales.map(s =>
        '<tr><td style="font-size:10px;color:#556">'+s.date.toLocaleString('pt-BR',{day:'2-digit',month:'2-digit',hour:'2-digit',minute:'2-digit'})+'</td>' +
        '<td><div class="item-name">'+escHtml(s.item)+'</div></td>' +
        '<td class="qty">'+s.qty.toLocaleString('pt-BR')+'</td>' +
        '<td class="price-tok">$'+s.unitPrice.toFixed(8).replace(/0+$/,'').replace(/[.]$/,'')+'</td>' +
        '<td class="price-tok">$'+s.usd.toFixed(2)+'</td></tr>').join('');
      // Group by day for chart
      const byDay = {};
      sales.forEach(s => {
        const day = s.date.toLocaleDateString('pt-BR',{day:'2-digit',month:'2-digit'});
        if (!byDay[day]) byDay[day] = 0;
        byDay[day] += s.usd;
      });
      const days = Object.keys(byDay).reverse();
      const vals = days.map(d => byDay[d]);
      const maxVal = Math.max(...vals) || 1;
      // SVG line chart
      const W = 600, H = 140, PL = 48, PR = 12, PT = 16, PB = 28;
      const cW = W - PL - PR, cH = H - PT - PB;
      const n = days.length;
      function cx(i) { return PL + (n < 2 ? cW/2 : i * cW / (n-1)); }
      function cy(v) { return PT + cH - Math.round((v/maxVal) * cH); }
