      const fillPts = 'M'+cx(0)+','+cy(vals[0])+' '+days.map((d,i)=>cx(i)+','+cy(vals[i])).join(' L')+' L'+cx(n-1)+','+(PT+cH)+' L'+cx(0)+','+(PT+cH)+' Z';
