    var $o = function(id){ return shadow.getElementById(id); };

    // Slider: searchrange
    $o('om-searchrange').addEventListener('input', function(){ $o('om-searchrange-val').textContent = this.value; });

    // Preview raio de busca no mapa 3D
    $o('om-preview-sr-btn').addEventListener('click', function() {
      agOptPreviewRadius(Number($o('om-searchrange').value), 0xf87171, 0xef4444); // vermelho
    });

    // Sliders: prioridade
    shadow.querySelectorAll('.om-pri').forEach(function(el) {
      el.addEventListener('input', function() {
        var v = parseFloat(this.value);
        $o('om-pri-val-' + this.dataset.type).textContent = v;
      });
    });

    // Slider: ruído
    $o('om-noise').addEventListener('input', function(){ $o('om-noise-val').textContent = Math.round(this.value*100)+'%'; });

    // Slider: pool
