  // Encontra um tile do portal para o realm destino (a partir do world)
  function agNavGetPortalTile(targetRealm) {
    // Usar try/catch em vez de typeof — mais robusto com imports ES module
    function fromSet(s) {
      try {
        if (!s || !s.size) return null;
        for (const k of s) {
          const [c,r] = k.split(',').map(Number);
          if (!isNaN(c) && !isNaN(r)) return {col:c, row:r};
        }
      } catch(_) {}
      return null;
    }
    try {
      if (targetRealm === 'pond') {
        return fromSet(Y3);  // pondPortalWorldSet
      }
      if (targetRealm === 'eldergrove') {
        // Primeiro tenta via eldergrovePortalWorldSet (J3)
        const t = fromSet(J3);
        if (t) return t;
        // Fallback via ELDERGROVE_PORTAL_COLS + ROW
        try {
          const col = Array.isArray(OM) ? OM[0] : OM;
          if (col != null && H7 != null) return {col, row: H7};
        } catch(_) {}
        return null;
      }
      if (targetRealm === 'wild' || targetRealm === 'wild_ext' || targetRealm === 'wild_exp') {
        // wildPortalWorldSet (qE)
        const t = fromSet(qE);
        if (t) return t;
        // Fallback via WILD_PORTAL_MID + ROW
        try { if (sg != null && Kw != null) return {col: sg, row: Kw}; } catch(_) {}
        return null;
      }
      if (targetRealm === 'beach') {
        // pond -> beach: pondBeachEntryTileSet (VE) — tile no pond que leva à beach
        return fromSet(VE);
      }
      if (targetRealm === 'ember') {
        // beach -> ember: beachEmberEntryTileSet (O7)
        return fromSet(O7);
      }
      if (targetRealm === 'frostmere') {
        // eldergrove -> frostmere: ek (eldergroveFrostmereEntryTileSet)
        return fromSet(ek);
      }
    } catch(e) {
      console.warn('[AutoGather] agNavGetPortalTile erro:', e.message);
    }
    return null;
  }

  function agNavDebug() {
    console.group('[AutoGather] Portal debug');
    try { console.log('Y3 (pond portal):', Y3 ? [...Y3].slice(0,3) : 'undefined'); } catch(e) { console.log('Y3 erro:', e.message); }
    try { console.log('J3 (eldergrove portal):', J3 ? [...J3].slice(0,3) : 'undefined'); } catch(e) { console.log('J3 erro:', e.message); }
    try { console.log('qE (wild portal):', qE ? [...qE].slice(0,3) : 'undefined'); } catch(e) { console.log('qE erro:', e.message); }
    try { console.log('OM (eldr portal cols):', OM, 'H7 (row):', H7); } catch(e) { console.log('eldergrove cols/row erro:', e.message); }
    try { console.log('sg (wild mid):', sg, '$w (row):', $w); } catch(e) { console.log('wild mid/row erro:', e.message); }
    try { console.log('L:', L, 'P:', P, 'gameState:', h); } catch(e) {}
    console.groupEnd();
  }
  window.__agNavDebug = agNavDebug;

  // Retorna o tile de saída (retorno ao world) do realm atual
  function agNavGetExitTile(fromRealm) {
    try {
      if (fromRealm === 'shack') {
        // Exit tiles do shack: [2,3], [0,4], [3,0], [3,1]
        // Usar [2,3] -- mais acessível (adjacente ao spawn [2,2])
        return { col: 2, row: 3 };
      }
      if (fromRealm === 'pond') {
        if (typeof V3 !== 'undefined' && V3.size > 0) {
          for (const k of V3) {
            const [c, r] = k.split(',').map(Number);
            if (!isNaN(c) && !isNaN(r)) return { col: c, row: r };
          }
        }
      }
      if (fromRealm === 'eldergrove') {
        if (typeof IM !== 'undefined' && IM.size > 0) {
          for (const k of IM) {
            const [c, r] = k.split(',').map(Number);
            if (!isNaN(c) && !isNaN(r)) return { col: c, row: r };
          }
        }
        if (typeof ELDERGROVE_RETURN_COLS !== 'undefined' && typeof ELDERGROVE_RETURN_ROW !== 'undefined') {
          const col = Array.isArray(ELDERGROVE_RETURN_COLS) ? ELDERGROVE_RETURN_COLS[0] : ELDERGROVE_RETURN_COLS;
          return { col, row: ELDERGROVE_RETURN_ROW };
        }
      }
      if (fromRealm === 'wild' || fromRealm === 'wild_ext' || fromRealm === 'wild_exp') {
        if (typeof qE !== 'undefined' && qE.size > 0) {
          for (const k of qE) {
            const [c, r] = k.split(',').map(Number);
            if (!isNaN(c) && !isNaN(r)) return { col: c, row: r };
          }
        }
      }
      if (fromRealm === 'beach') {
        // beachReturnSet (KE) = tiles da beach que levam de volta ao pond
        if (typeof KE !== 'undefined' && KE.size > 0) {
          for (const k of KE) {
            const [c, r] = k.split(',').map(Number);
            if (!isNaN(c) && !isNaN(r)) return { col: c, row: r };
          }
        }
      }
      if (fromRealm === 'frostmere') {
        if (typeof cg !== 'undefined' && cg.size > 0) {
          for (const k of cg) {
            const [c, r] = k.split(',').map(Number);
            if (!isNaN(c) && !isNaN(r)) return { col: c, row: r };
          }
        }
      }
      if (fromRealm === 'ember') {
        if (typeof X3 !== 'undefined' && X3.size > 0) {
          for (const k of X3) {
            const [c, r] = k.split(',').map(Number);
            if (!isNaN(c) && !isNaN(r)) return { col: c, row: r };
          }
        }
      }
    } catch(e) {}
    return null;
  }

  function agNavTick() {
    if (!agNavTarget) return;

    // Já chegou no destino
    if (h === agNavTarget) {
      agNavTarget = null;
      clearTimeout(agNavTimer);
      agNavSetStatus('');
      if (agActive && agMode === 'fish') {
        agSetStatus('🎣 No mapa certo! Iniciando pesca…');
      }
      return;
    }

    // Se destino é o realm atual mas via world — já está no destino
    if (h === 'world' && agNavTarget === 'world') {
      agNavTarget = null; agNavSetStatus(''); return;
    }

    // Se não está no world, precisa sair primeiro pelo portal de retorno
    if (h !== 'world') {
      const exit = agNavGetExitTile(h);
      if (!exit) {
        agNavSetStatus('⚠️ Sem saída conhecida de ' + (AG_REALM_LABELS[h] || h));
        agNavTimer = setTimeout(agNavTick, 2000);
        return;
      }
      // Já está no tile de saída — aguarda transição
      if (L === exit.col && P === exit.row) {
        agNavSetStatus('🌀 Saindo de ' + (AG_REALM_LABELS[h] || h) + '…');
        agNavTimer = setTimeout(agNavTick, 500);
        return;
      }
      // Caminha até o tile de saída
      const distToExit = Math.abs(L - exit.col) + Math.abs(P - exit.row);
      if (distToExit <= 1) {
        agNavSetStatus('🌀 Saindo de ' + (AG_REALM_LABELS[h] || h) + '…');
        agNavTimer = setTimeout(agNavTick, 500);
        return;
      }
      const path = qn(L, P, exit.col, exit.row);
      if (!path || !path.length) {
        agNavSetStatus('❌ Sem caminho para saída de ' + (AG_REALM_LABELS[h] || h));
        agNavTimer = setTimeout(agNavTick, 2000);
        return;
      }
      Y = path;
      if (!q) Jn();
      agNavSetStatus('🚶 Saindo de ' + (AG_REALM_LABELS[h] || h) + ' → ' + (AG_REALM_LABELS[agNavTarget] || agNavTarget) + '…');
      agNavTimer = setTimeout(agNavTick, 500);
      return;
    }

    // Está no world — multi-hop para beach/ember via pond
    // beach e ember não são acessíveis diretamente do world
    var _effectiveTarget = agNavTarget;
    if (agNavTarget === 'beach' || agNavTarget === 'ember') {
      _effectiveTarget = 'pond'; // vai para pond primeiro
    }

    // Está no world — vai para o portal do destino
    const portal = agNavGetPortalTile(_effectiveTarget);
    if (!portal) {
      agNavSetStatus('❌ Portal não encontrado — veja console (F12)');
      console.warn('[AutoGather] Portal não encontrado para:', agNavTarget);
      agNavDebug();
      agNavTarget = null; return;
    }

    // Pond->beach multi-hop: se destino é ember e estamos no pond, ir para beach
    if (h === 'pond' && agNavTarget === 'ember') {
      _effectiveTarget = 'beach';
      const beachPortal = agNavGetPortalTile('beach');
      if (beachPortal) {
        if (L === beachPortal.col && P === beachPortal.row) {
          agNavSetStatus('🌀 Entrando na Beach…');
          agNavTimer = setTimeout(agNavTick, 500); return;
        }
        const bp = qn(L, P, beachPortal.col, beachPortal.row);
        if (bp && bp.length) { Y = bp; if (!q) Jn(); }
        agNavSetStatus('🚶 Indo para Beach (caminho para Ember)…');
        agNavTimer = setTimeout(agNavTick, 500); return;
      }
    }

    // Verifica se já está no tile do portal (transição automática)
    if (L === portal.col && P === portal.row) {
      agNavSetStatus('🌀 Entrando em ' + (AG_REALM_LABELS[agNavTarget] || agNavTarget) + '…');
      agNavTimer = setTimeout(agNavTick, 500);
      return;
    }

    // Caminha até o portal
    const path = qn(L, P, portal.col, portal.row);
    if (!path || !path.length) {
      agNavSetStatus('❌ Sem caminho para o portal');
      agNavTarget = null; return;
    }
    Y = path;
    if (!q) Jn();
    agNavSetStatus('🚶 Indo para ' + (AG_REALM_LABELS[agNavTarget] || agNavTarget) + '…');
    agNavTimer = setTimeout(agNavTick, 500);
  }

  function agNavTo(realm) {
    if (h === realm) {
      agNavSetStatus('✓ Já estás em ' + (AG_REALM_LABELS[realm] || realm));
      return;
    }
    agNavTarget = realm;
    clearTimeout(agNavTimer);
    agNavTick();
  }

  function agNavCancel() {
    agNavTarget = null;
    clearTimeout(agNavTimer);
    agNavSetStatus('');
  }

